python3 << 'EOF'
with open('/workspace/YatCC/task/2/antlr/Ast2Asg.cpp', 'rb') as f:
    content = f.read()

# Check for any null bytes or other unusual bytes
bad_bytes = []
for i, b in enumerate(content):
    if b == 0:
        bad_bytes.append(i)

if bad_bytes:
    print(f"Found {len(bad_bytes)} null bytes at positions: {bad_bytes[:10]}")
else:
    print("No null bytes found")

# Check for other unusual patterns
if b'\xef\xbb\xbf' in content:
    print("Found UTF-8 BOM")

# Check for Windows line endings
if b'\r\n' in content:
    print("Found Windows line endings (CRLF)")

# Check for only CR
if b'\r' in content and b'\r\n' not in content:
    print("Found old Mac line endings (CR only)")
EOF

